        "path": "ark-survival-evolved-trainer/ark-survival-evolved-trainer.csproj",
        "content": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net8.0</TargetFramework>\n    <RootNamespace>ArkSurvivalEvolvedTrainer</RootNamespace>\n    <AssemblyName>ArkSurvivalEvolvedTrainer</AssemblyName>\n    <Nullable>enable</Nullable>\n    <ImplicitUsings>enable</ImplicitUsings>\n  </PropertyGroup>\n  <ItemGroup>\n    <PackageReference Include=\"Memory.dll\" Version=\"1.0.0\" />\n  </ItemGroup>\n</Project>"
