    {
        "path": "ark-survival-evolved-trainer/Program.cs",
        "content": "using ArkSurvivalEvolvedTrainer.Core;\nusing ArkSurvivalEvolvedTrainer.UI;\n\nnamespace ArkSurvivalEvolvedTrainer;\n\n/// <summary>\n/// Entry point for the ARK: Survival Evolved Trainer.\n/// Initializes memory access, UI, and hotkey listeners.\n/// </summary>\npublic static class Program\n{\n    public static void Main()\n    {\n        Console.Title = \"ARK: Survival Evolved Trainer v1.0\";\n        Console.WriteLine(\"Initializing trainer...\");\n\n        using var memoryManager = new MemoryManager(\"ShooterGame\");\n        var trainer = new TrainerCore(memoryManager);\n        var consoleUi = new ConsoleUI(trainer);\n\n        consoleUi.Run();\n    }\n}"
    },
    {
        "path": "ark-survival-evolved-trainer/Core/MemoryManager.cs",
        "content": "using System.Diagnostics;\nusing Memory;\n\nnamespace ArkSurvivalEvolvedTrainer.Core;\n\n/// <summary>\n/// Manages low-level memory operations for the ARK process.\n/// Uses the Memory.dll library for reading/writing process memory.\n/// </summary>\npublic sealed class MemoryManager : IDisposable\n{\n    private readonly Mem _memLib;\n    private readonly IntPtr _baseAddress;\n\n    /// <summary>\n    /// Initializes a new instance of the <see cref=\"MemoryManager\"/> class.\n    /// </summary>\n    /// <param name=\"processName\">The name of the target process (without .exe).</param>\n    /// <exception cref=\"InvalidOperationException\">Thrown if process not found.</exception>\n    public MemoryManager(string processName)\n    {\n        _memLib = new Mem();\n        var pid = _memLib.GetProcIdFromName(processName);\n        if (pid == 0)\n            throw new InvalidOperationException($\"Process '{processName}' not found. Ensure ARK is running.\");\n\n        _memLib.OpenProcess(pid);\n        _baseAddress = _memLib.GetModuleBaseAddress(processName);\n        Console.WriteLine($\"Attached to {processName} (PID: {pid}, Base: 0x{_baseAddress:X})\");\n    }\n\n    /// <summary>\n    /// Reads an integer value from a memory address using a pointer path.\n    /// </summary>\n    /// <param name=\"offsets\">Array of offsets forming the pointer chain.</param>\n    /// <returns>The integer value at the resolved address.</returns>\n    public int ReadInt(params int[] offsets)\n    {\n        var address = _memLib.GetCode(true, \"int\", _baseAddress, offsets);\n        if (address == IntPtr.Zero)\n            return 0;\n\n        return _memLib.ReadInt(address);\n    }\n\n    /// <summary>\n    /// Writes an integer value to a memory address using a pointer path.\n    /// </summary>\n    /// <param name=\"value\">The value to write.</param>\n    /// <param name=\"offsets\">Array of offsets forming the pointer chain.</param>\n    public void WriteInt(int value, params int[] offsets)\n    {\n        var address = _memLib.GetCode(true, \"int\", _baseAddress, offsets);\n        if (address != IntPtr.Zero)\n            _memLib.WriteMemory(address, \"int\", value.ToString());\n    }\n\n    /// <summary>\n    /// Reads a float value from a memory address using a pointer path.\n    /// </summary>\n    /// <param name=\"offsets\">Array of offsets forming the pointer chain.</param>\n    /// <returns>The float value at the resolved address.</returns>\n    public float ReadFloat(params int[] offsets)\n    {\n        var address = _memLib.GetCode(true, \"float\", _baseAddress, offsets);\n        if (address == IntPtr.Zero)\n            return 0.0f;\n\n        return _memLib.ReadFloat(address);\n    }\n\n    /// <summary>\n    /// Writes a float value to a memory address using a pointer path.\n    /// </summary>\n    /// <param name=\"value\">The value to write.</param>\n    /// <param name=\"offsets\">Array of offsets forming the pointer chain.</param>\n    public void WriteFloat(float value, params int[] offsets)\n    {\n        var address = _memLib.GetCode(true, \"float\", _baseAddress, offsets);\n        if (address != IntPtr.Zero)\n            _memLib.WriteMemory(address, \"float\", value.ToString(\"F6\"));\n    }\n\n    /// <summary>\n    /// Reads a boolean value from a memory address using a pointer path.\n    /// </summary>\n    /// <param name=\"offsets\">Array of offsets forming the pointer chain.</param>\n    /// <returns>True if the byte is non-zero, otherwise false.</returns>\n    public bool ReadBool(params int[] offsets)\n    {\n        var address = _memLib.GetCode(true, \"byte\", _baseAddress, offsets);\n        if (address == IntPtr.Zero)\n            return false;\n\n        return _memLib.ReadByte(address) != 0;\n    }\n\n    /// <summary>\n    /// Writes a boolean value to a memory address using a pointer path.\n    /// </summary>\n    /// <param name=\"value\">The boolean value to write.</param>\n    /// <param name=\"offsets\">Array of offsets forming the pointer chain.</param>\n    public void WriteBool(bool value, params int[] offsets)\n    {\n        var address = _memLib.GetCode(true, \"byte\", _baseAddress, offsets);\n        if (address != IntPtr.Zero)\n            _memLib.WriteMemory(address, \"byte\", value ? \"1\" : \"0\");\n    }\n\n    public void Dispose()\n    {\n        _memLib.CloseProcess();\n    }\n}"
    },
