        "path": "ark-survival-evolved-trainer/Core/TrainerCore.cs",
        "content": "namespace ArkSurvivalEvolvedTrainer.Core;\n\n/// <summary>\n/// Core trainer logic: manages cheats and memory addresses for ARK.\n/// Provides methods to toggle god mode, infinite stats, and item spawning.\n/// </summary>\npublic sealed class TrainerCore\n{\n    private readonly MemoryManager _memory;\n\n    // Example pointer paths (offsets) — these are illustrative; real offsets change with game updates.\n    // Typically found via Cheat Engine or ReClass.NET.\n    private const int LocalPlayerOffset = 0x12345678;\n    private const int HealthOffset = 0x100;\n    private const int StaminaOffset = 0x104;\n    private const int OxygenOffset = 0x108;\n    private const int FoodOffset = 0x10C;\n    private const int WaterOffset = 0x110;\n    private const int WeightOffset = 0x114;\n    private const int GodModeOffset = 0x118;\n\n    /// <summary>\n    /// Initializes a new instance of the <see cref=\"TrainerCore\"/> class.\n    /// </summary>\n    /// <param name=\"memory\">An initialized <see cref=\"MemoryManager\"/> instance.</param>\n    public TrainerCore(MemoryManager memory)\n    {\n        _memory = memory;\n    }\n\n    /// <summary>\n    /// Toggles god mode (invulnerability). Sets health to a high value and prevents damage.\n    /// </summary>\n    /// <param name=\"enable\">True to enable god mode, false to disable.</param>\n    public void SetGodMode(bool enable)\n    {\n        // In practice, this might write to a specific byte that controls damage reception.\n        _memory.WriteBool(enable, LocalPlayerOffset, GodModeOffset);\n        if (enable)\n        {\n            // Set health to a large value as a failsafe.\n            _memory.WriteFloat(99999.0f, LocalPlayerOffset, HealthOffset);\n        }\n        Console.WriteLine($\"God mode {(enable ? \"enabled\" : \"disabled\")}.\");\n    }\n\n    /// <summary>\n    /// Refills health to maximum.\n    /// </summary>\n    public void RefillHealth()\n    {\n        _memory.WriteFloat(100.0f, LocalPlayerOffset, HealthOffset);\n        Console.WriteLine(\"Health refilled.\");\n    }\n\n    /// <summary>\n    /// Refills stamina to maximum.\n    /// </summary>\n    public void RefillStamina()\n    {\n        _memory.WriteFloat(100.0f, LocalPlayerOffset, StaminaOffset);\n        Console.WriteLine(\"Stamina refilled.\");\n    }\n\n    /// <summary>\n    /// Refills oxygen, food, and water (basic survival stats).\n    /// </summary>\n    public void RefillSurvivalStats()\n    {\n        _memory.WriteFloat(100.0f, LocalPlayerOffset, OxygenOffset);\n        _memory.WriteFloat(100.0f, LocalPlayerOffset, FoodOffset);\n        _memory.WriteFloat(100.0f, LocalPlayerOffset, WaterOffset);\n        Console.WriteLine(\"Survival stats refilled (O2, Food, Water).\");\n    }\n\n    /// <summary>\n    /// Sets player weight to a very high value (effectively unlimited carry capacity).\n    /// </summary>\n    public void SetInfiniteWeight()\n    {\n        _memory.WriteFloat(99999.0f, LocalPlayerOffset, WeightOffset);\n        Console.WriteLine(\"Weight set to 99999 (infinite carry capacity).\");\n    }\n\n    /// <summary>\n    /// Spawns a specified item into the player's inventory.\n    /// NOTE: This is a simplified placeholder; actual item spawning requires complex bytecode injection.\n    /// </summary>\n    /// <param name=\"itemId\">The item blueprint ID (e.g., \"PrimalItem_WeaponGun_C\").</param>\n    /// <param name=\"quantity\">Number of items to spawn.</param>\n    public void SpawnItem(string itemId, int quantity)\n    {\n        // In a real trainer, this would involve calling an internal game function via code injection.\n        // For demonstration, we log the action.\n        Console.WriteLine($\"Spawning {quantity}x {itemId} (injection placeholder).\");\n    }\n\n    /// <summary>\n    /// Gets the current health value of the player.\n    /// </summary>\n    /// <returns>Current health as float.</returns>\n    public float GetHealth()\n    {\n        return _memory.ReadFloat(LocalPlayerOffset, HealthOffset);\n    }\n\n    /// <summary>\n    /// Gets the current stamina value of the player.\n    /// </summary>\n    /// <returns>Current stamina as float.</returns>\n    public float GetStamina()\n    {\n        return _memory.ReadFloat(LocalPlayerOffset, StaminaOffset);\n    }\n}"
    },
    {
        "path": "ark-survival-evolved-trainer/UI/ConsoleUI.cs",
        "content": "using ArkSurvivalEvolvedTrainer.Core;\n\nnamespace ArkSurvivalEvolvedTrainer.UI;\n\n/// <summary>\n/// Simple console-based user interface for the trainer.\n/// Listens for keyboard input and triggers trainer functions.\n/// </summary>\npublic sealed class ConsoleUI\n{\n    private readonly TrainerCore _trainer;\n    private bool _running;\n\n    /// <summary>\n    /// Initializes a new instance of the <see cref=\"ConsoleUI\"/> class.\n    /// </summary>\n    /// <param name=\"trainer\">The trainer core instance.</param>\n    public ConsoleUI(TrainerCore trainer)\n    {\n        _trainer = trainer;\n    }\n\n    /// <summary>\n    /// Starts the UI loop that processes user input.\n    /// </summary>\n    public void Run()\n    {\n        _running = true;\n        DisplayHelp();\n\n        while (_running)\n        {\n            Console.Write(\"\\nEnter command (or 'help'): \");\n            var input = Console.ReadLine()?.Trim().ToLowerInvariant();\n\n            switch (input)\n            {\n                case \"god\":\n                    _trainer.SetGodMode(true);\n                    break;\n                case \"ungod\":\n                    _trainer.SetGodMode(false);\n                    break;\n                case \"health\":\n                    _trainer.RefillHealth();\n                    break;\n                case \"stamina\":\n                    _trainer.RefillStamina();\n                    break;\n                case \"survival\":\n                    _trainer.RefillSurvivalStats();\n                    break;\n                case \"weight\":\n                    _trainer.SetInfiniteWeight();\n                    break;\n                case \"status\":\n                    Console.WriteLine($\"Health: {_trainer.GetHealth():F1}, Stamina: {_trainer.GetStamina():F1}\");\n                    break;\n                case \"help\":\n                    DisplayHelp();\n                    break;\n                case \"exit\":\n                    _running = false;\n                    Console.WriteLine(\"Exiting trainer.\");\n                    break;\n                default:\n                    Console.WriteLine($\"Unknown command: '{input}'. Type 'help' for commands.\");\n                    break;\n            }\n        }\n    }\n\n    private void DisplayHelp()\n    {\n        Console.WriteLine(\"\\n=== ARK: Survival Evolved Trainer ===\");\n        Console.WriteLine(\"Commands:\");\n        Console.WriteLine(\"  god       - Enable god mode (invulnerability)\");\n        Console.WriteLine(\"  ungod     - Disable god mode\");\n        Console.WriteLine(\"  health    - Refill health\");\n        Console.WriteLine(\"  stamina   - Refill stamina\");\n        Console.WriteLine(\"  survival  - Refill O2, food, water\");\n        Console.WriteLine(\"  weight    - Set infinite weight\");\n        Console.WriteLine(\"  status    - Show current health/stamina\");\n        Console.WriteLine(\"  help      - Show this help\");\n        Console.WriteLine(\"  exit      - Exit trainer\");\n        Console.WriteLine(\"=====================================\");\n    }\n}"
    },
    {
        "path": "ark-survival-evolved-trainer/Tests/TrainerCoreTests.cs",
        "content": "using Xunit;\nusing Moq;\nusing ArkSurvivalEvolvedTrainer.Core;\n\nnamespace ArkSurvivalEvolvedTrainer.Tests;\n\n/// <summary>\n/// Unit tests for TrainerCore using a mocked MemoryManager.\n/// Validates that trainer methods call the correct memory operations.\n/// </summary>\npublic class TrainerCoreTests\n{\n    [Fact]\n    public void SetGodMode_Enabled_WritesTrueAndSetsHealth()\n    {\n        // Arrange\n        var mockMemory = new Mock<MemoryManager>(\"dummy\");\n        var trainer = new TrainerCore(mockMemory.Object);\n\n        // Act\n        trainer.SetGodMode(true);\n\n        // Assert\n        mockMemory.Verify(m => m.WriteBool(true, 0x12345678, 0x118), Times.Once);\n        mockMemory.Verify(m => m.WriteFloat(99999.0f, 0x12345678, 0x100), Times.Once);\n    }\n\n    [Fact]\n    public void SetGodMode_Disabled_WritesFalse()\n    {\n        // Arrange\n        var mockMemory = new Mock<MemoryManager>(\"dummy\");\n        var trainer = new TrainerCore(mockMemory.Object);\n\n        // Act\n        trainer.SetGodMode(false);\n\n        // Assert\n        mockMemory.Verify(m => m.WriteBool(false, 0x12345678, 0x118), Times.Once);\n        mockMemory.Verify(m => m.WriteFloat(It.IsAny<float>(), It.IsAny<int>(), It.IsAny<int>()), Times.Never);\n    }\n\n    [Fact]\n    public void RefillHealth_WritesMaxHealth()\n    {\n        // Arrange\n        var mockMemory = new Mock<MemoryManager>(\"dummy\");\n        var trainer = new TrainerCore(mockMemory.Object);\n\n        // Act\n        trainer.RefillHealth();\n\n        // Assert\n        mockMemory.Verify(m => m.WriteFloat(100.0f, 0x12345678, 0x100), Times.Once);\n    }\n\n    [Fact]\n    public void RefillStamina_WritesMaxStamina()\n    {\n        // Arrange\n        var mockMemory = new Mock<MemoryManager>(\"dummy\");\
